---战斗阴影
---@class LFightFade
local LFightFade = LxClass("LFightFade", nil)
local typeSpriteRenderer = typeof(UnityEngine.SpriteRenderer)


LFightFade.TYPE_ONE = 1
LFightFade.TYPE_TWO = 2
LFightFade.TYPE_THREE = 3
LFightFade.TYPE_FOUR = 4


function LFightFade:LFightFade()
    self._path = "Map/Prefabs"
    self._name = "MapFade"

    ---@type LDisplayPrefab
    self._dpPrefab = nil
end

function LFightFade:Create(para)
    self._parentRoot = para.parentRoot
    self._startTime = para.startTime

    self._playTime = self._startTime + para.playTime

    self._dissipateTime = self._playTime + para.dissipateTime

    self._fadeOutStart = self._playTime
    self._fadeOutSpan = para.dissipateTime
    self._fadeOutEnd = self._dissipateTime

    self._fadeInStart = self._startTime
    self._fadeInSpan = para.dissipateTime
    self._fadeInEnd = self._startTime+ self._fadeInSpan

    self._renderLayer = para.layer
    self._renderOrder = para.order

    self._callback = para.callback

    self._alpha = tonumber(para.alpha) or 0


    self._type = para.type or LFightFade.TYPE_TWO

    self._side = para.side
    self._index = para.index
    if CS.IsValidObject(self._fadeGo) then
        self._isDestroy = false
        self._isPlaying = false
        return
    else
        self:StartLoad()
    end
end

function LFightFade:StartLoad()
    self._isFromScene = false
    if self._cloneGo then
        LxResUtil.DestroyObject(self._cloneGo)
        self._cloneGo= nil
    end
    local scene = GF.GetMainScene()
    if scene then
        local mapFade = scene:GetMapFade()
        if CS.IsValidObject(mapFade) then
            self._isFromScene = true
            local cloneGo = LxResUtil.NewObject(mapFade.gameObject)
            self._cloneGo = cloneGo
            cloneGo.name = mapFade.name
            self:OnLoaded(cloneGo.transform)
            return
        end
    end

    self:ClearPrefab()
    local dpPrefab = LDisplayPrefab:New()
    self._dpPrefab = dpPrefab
    dpPrefab:CreatePrefab(self._parentRoot, self._path, self._name)
    dpPrefab:SetLoadedFunction(function (dp)
        local instanceTrans = dp:GetDisplayTrans()
        self:OnLoaded(instanceTrans)
    end)
    dpPrefab:StartLoad()
end

function LFightFade:OnLoaded(instanceTrans)
    if not CS.IsValidObject(instanceTrans) then return end

    local instanceGo = instanceTrans.gameObject

    CS.ShowObject(instanceGo,false)
    self._fadeGo = instanceGo

    local scale = Vector3.New(30,30,0)
    if self._type == LFightFade.TYPE_THREE then
        scale = Vector3.New(5000,5000,0)
        local dpGo = instanceGo.gameObject
        if dpGo.layer ~= LWnd.WND_LAYER then
            CS.UpdateChildLayer(instanceGo.transform, LWnd.WND_LAYER)
        end
    end
    self._fadeGo.transform.localScale = scale
    self._fadeGo.transform.localPosition= Vector3.zero
    self:UpdateRender()
    self:SetAlpha(0)
    local show = self._isPlaying == true
    CS.ShowObject(instanceGo,show)
end

function LFightFade:ClearPrefab()
    if self._dpPrefab then
        self._dpPrefab:Destroy()
        self._dpPrefab = nil
    end
end

function LFightFade:Destroy()
    if self._isDestroy then return end
    self:PlayCallback()
    if self._cloneGo then
        LxResUtil.DestroyObject(self._cloneGo)
        self._cloneGo = nil
    end
    self:ClearPrefab()
    table.removeall(self)
    self._isDestroy = true
end
-----------------------------------------------------------------
function LFightFade:OnRun(time)
    if self._isDestroy then return false end
    if not self._isPlaying then
        if self._startTime <= time then
            self._isPlaying = true
            self._sendShow = false
            self._sendHide = false
            CS.ShowObject(self._fadeGo,true)
        end
    else

        --local str = string.format("time %s|inS %s|inE %s|outS %s|outE %s",time,self._fadeInStart,self._fadeInEnd,self._fadeOutStart,self._fadeOutEnd)
        --printInfoN(str)
        --printInfoN("alpha "..self._alpha)
        if time < self._fadeInEnd and time >= self._fadeInStart then
            if self._fadeInSpan>0 then
                local timeLeft =  time - self._fadeInStart
                local percent =Mathf.Lerp(0,1,timeLeft/self._fadeInSpan)
                local alpha = percent * self._alpha
                self:SetAlpha(alpha)
            end

            if self._type == LFightFade.TYPE_TWO and not self._sendHide  then
                self._sendHide = true
                FireEvent(EventNames.CHANGE_BATTLE_WND_SHOW,false,self._fadeInSpan,self._side,self._index)
            end

        elseif time > self._fadeInEnd and time < self._fadeOutStart then
            self:SetAlpha(self._alpha)
        elseif time < self._fadeOutEnd and time >= self._fadeOutStart then
            if self._fadeOutSpan> 0 then
                local timeLeft = self._fadeOutEnd - time
                local percent =Mathf.Lerp(0,1,timeLeft/self._fadeOutSpan)
                local alpha = percent * self._alpha
                self:SetAlpha(alpha)
            end

            if self._type == LFightFade.TYPE_TWO and not self._sendShow then
                self._sendShow = true
                FireEvent(EventNames.CHANGE_BATTLE_WND_SHOW,true,self._fadeOutSpan,self._side,self._index)
            end
        end

        if self._dissipateTime < time  then
            self:PlayCallback()
            return false
        end
    end
    return true
end

function LFightFade:PlayCallback()
    if self._callback then
        local callback = self._callback
        self._callback = nil
        callback()
    end
end

function LFightFade:SetRenderOrder(order)
    self._renderOrder = order
    self:UpdateRender()
end

function LFightFade:UpdateRender()
    if not CS.IsValidObject(self._fadeGo) then
        return
    end
    if not self._sr then
        self._sr = self._fadeGo:GetComponent(typeSpriteRenderer)
    end

    self._sr.sortingOrder = self._renderOrder or 0
    self._sr.sortingLayerName = self._renderLayer or "Default"
end

function LFightFade:SetAlpha(alpha)
    if not CS.IsValidObject(self._fadeGo) then
        return
    end
    if not self._sr then
        self._sr = self._fadeGo:GetComponent(typeSpriteRenderer)
    end

    local value = alpha/255
    self._sr.color = Color.New(0, 0, 0, value)
end

return LFightFade